func goMinorVersion(version string) int {
	if strings.HasPrefix(version, "devel") {
		return 9999
	}
	var major, minor int
	var trailing string
	n, err := fmt.Sscanf(version, "go%d.%d%s", &major, &minor, &trailing)
	if n == 2 && err == io.EOF {

		err = nil
	}
	if err != nil {
		return 0
	}
	return minor
}
